module top_module(
  input wire in1,
  input wire in2,
  input wire Cin,
  output wire S,
  output wire Cout
  );wire XOR1;
  wire XOR2;
  wire AND1;
  wire AND3;
  wire OR4;

  assign XOR1 = in1 ^ in2;
  assign XOR2 = XOR1 ^ Cin;
  wire temp1_XOR1 = XOR1;
  wire temp2_Cin = Cin;
  assign AND3 = temp1_XOR1 & temp2_Cin;
  assign AND1 = in1 & in2;
  assign OR4  = AND3 | AND1;

  assign S = XOR2;
  assign Cout = OR4;


endmodule
